import React, { useEffect, useState } from "react";
import { WS } from "./../utils/websocket";
import { useSelector } from "react-redux";

import { Form, Input, Button, Space } from "antd";

const tailLayout = {
  wrapperCol: { offset: 12, span: 16 },
};

const updateConfigs = (data) => {
  const pattern = /speed/;
  return Object.keys(data)
    .filter((key) => {
      if (pattern.test(key)) {
        if (key === "planning_upper_speed_limit") {
          return true;
        }
        return false;
      }
      return true;
    })
    .reduce((obj, key) => {
      obj[key] = data[key];
      return obj;
    }, {});
};

const EditSetting = () => {
  const vehicleConfig = useSelector((state) => state.setting.vehicleConfig);
  const [vehicleConfigData, setVehicleConfigData] = useState({});

  useEffect(() => {
    WS.getVehicleConfig();
  }, []);

  useEffect(() => {
    const data = updateConfigs(vehicleConfig);
    setVehicleConfigData(data);
  }, [vehicleConfig]);

  const handleCancelEditProfile = () => {
    WS.getVehicleConfig();
  };

  const handleSaveEditProfile = () => {
    const pattern = /speed/;
    const allVehicleConfig = Object.keys(vehicleConfig).reduce((obj, key) => {
      if (pattern.test(key)) {
        obj[key] = vehicleConfigData["planning_upper_speed_limit"];
        return obj;
      }
      obj[key] = vehicleConfig[key];
      return obj;
    }, {});
    console.log(allVehicleConfig, vehicleConfigData, vehicleConfig);

    WS.modifyVehicleConfig(allVehicleConfig);
  };

  const handleChange = (key, event) => {
    const value = event.target.value;

    const data = {
      ...vehicleConfigData,
      [key]: value,
    };
    setVehicleConfigData(data);
  };

  return (
    <div>
      <Form
        labelCol={{ span: 8 }}
        wrapperCol={{ span: 16 }}
        layout="horizontal"
        size={"large"}
        style={{ maxWidth: 1000, marginTop: 20 }}
      >
        {Object.keys(vehicleConfigData).map((key) => {
          return (
            <Form.Item label={key} key={key}>
              <Input
                placeholder="Please enter"
                value={vehicleConfigData[key]}
                onChange={(e) => handleChange(key, e)}
              />
            </Form.Item>
          );
        })}
        <Form.Item {...tailLayout}>
          <Space>
            <Button
              type="primary"
              htmlType="submit"
              onClick={() => handleCancelEditProfile()}
            >
              Cancel
            </Button>
            <Button
              type="primary"
              htmlType="button"
              onClick={() => handleSaveEditProfile()}
            >
              Confirm
            </Button>
          </Space>
        </Form.Item>
      </Form>
    </div>
  );
};

export default EditSetting;
